INSERT INTO `projets` (`id`, `ref`, `title`, `service`, `parentProjectId`, `projectType`, `description`, `color`, `customColor`, `start`, `duration`, `lane`, `startExact`, `endExact`, `riskGain`, `budgetEstimate`, `prioritization`, `status`, `progression`, `youtrackId`, `youtrackUrl`, `ownerId`, `ownerDisplayName`, `ownerEmail`, `teamMembers`, `taskColumns`, `created_at`, `updated_at`) VALUES ('prj001','PRJ001','Justification des comptes 402 pour les CAC','Comptabilité','prja45e47bd','Maintenance','Chantier déjà entamé et en cours (6832,8411)\nLes comptes 402 étant centralisés dans Sage, nous avons besoin du détail de chacune des centralisations afin d\'en rendre compte aux CAC qui nous les demande. Entre 2019 et 2023, un gros écart s\'est creusé laissant apparaitre un solde de 500K entre les émissions et les encaissements. L\'objectif est de déterminer pourquoi. Depuis 2023, cet écart ne semble plus évoluer ou dans une moindre mesure.',NULL,NULL,'2026-01-15',9,44,'2026-01-15','2026-05-31','Règlementaire vs CAC','Associé au projet PRJ004 (4K)','à lancer ASAP','Planifié',30,NULL,NULL,'Admin','Merouan Hamzaoui','m.hamzaoui@adep.com','[]','[\"idReadable\",\"summary\",\"assignee\",\"dueDate\",\"state\"]','2026-04-03 16:31:42','2026-04-04 18:49:25');
INSERT INTO `projets` (`id`, `ref`, `title`, `service`, `parentProjectId`, `projectType`, `description`, `color`, `customColor`, `start`, `duration`, `lane`, `startExact`, `endExact`, `riskGain`, `budgetEstimate`, `prioritization`, `status`, `progression`, `youtrackId`, `youtrackUrl`, `ownerId`, `ownerDisplayName`, `ownerEmail`, `teamMembers`, `taskColumns`, `created_at`, `updated_at`) VALUES ('prj002','PRJ002','GED Apporteur','Comptabilité / Marketing',NULL,'Maintenance','Pouvoir déposer dans OA les documents relatifs à chaque apporteur afin que cela remonte dans leur espace DEMAT. Exemple concret d\'utilisation :\nMise en dispo DADS (compta), des protocoles de commercialisation (RH)\nSécurise les données transmises car actuellement envoyées par mail.\nNOMA a déjà établi le devis et John a déjà travaillé avec Pascale sur la mise en place.','#a026f7','#a026f7',NULL,NULL,NULL,NULL,NULL,NULL,'Voir devis noma','StdBy','Standby',0,NULL,NULL,'Admin','Merouan Hamzaoui','m.hamzaoui@adep.com','[]','[\"idReadable\",\"summary\",\"assignee\",\"dueDate\",\"state\"]','2026-04-03 16:31:42','2026-04-04 18:49:25');
INSERT INTO `projets` (`id`, `ref`, `title`, `service`, `parentProjectId`, `projectType`, `description`, `color`, `customColor`, `start`, `duration`, `lane`, `startExact`, `endExact`, `riskGain`, `budgetEstimate`, `prioritization`, `status`, `progression`, `youtrackId`, `youtrackUrl`, `ownerId`, `ownerDisplayName`, `ownerEmail`, `teamMembers`, `taskColumns`, `created_at`, `updated_at`) VALUES ('prj003','PRJ003','Nouveau prestataire pour envoyer SMS Contentieux OA','Comptabilité / IT','prja45e47bd','Maintenance','Fin MAILEVA : fin juin 2026.\nRecouvrement des impayés / impact financier si cela ne fonctionne plus.\nÉtablir un nouveau reporting (l’actuel n’est pas exploitable).\nAction : trouver nouveau prestataire (intégrer l\'envoi mail à voir), gestion RMS...\nNoms évoqués : SMS Partner, Brevo, M Target',NULL,NULL,'2026-05-01',4,23,'2026-05-01','2026-06-30','Arrêt de service SMS','3K setup + budget mensuel lié au quantité','30/06 arrêt service','Planifié',0,NULL,NULL,'Admin','Merouan Hamzaoui','m.hamzaoui@adep.com','[]','[\"idReadable\",\"summary\",\"assignee\",\"dueDate\",\"state\"]','2026-04-03 16:31:42','2026-04-04 18:49:25');
INSERT INTO `projets` (`id`, `ref`, `title`, `service`, `parentProjectId`, `projectType`, `description`, `color`, `customColor`, `start`, `duration`, `lane`, `startExact`, `endExact`, `riskGain`, `budgetEstimate`, `prioritization`, `status`, `progression`, `youtrackId`, `youtrackUrl`, `ownerId`, `ownerDisplayName`, `ownerEmail`, `teamMembers`, `taskColumns`, `created_at`, `updated_at`) VALUES ('prj004','PRJ004','Reporting émissions','Comptabilité','prja45e47bd','Maintenance','-->Certaines données sont manquantes dans les reportings Emissions actuel. Il faut envisager un programme dans OA permettant d\'assurer la traçabilité des données extraites',NULL,NULL,'2026-03-01',4,22,'2026-03-01','2026-04-30','Assureur, non conformité relevée par le contrôleur de gestion VS','Associé au projet PRJ001 (4K)','à lancer ASAP','Planifié',40,NULL,NULL,'Admin','Merouan Hamzaoui','m.hamzaoui@adep.com','[]','[\"idReadable\",\"summary\",\"assignee\",\"dueDate\",\"state\"]','2026-04-03 16:31:42','2026-04-04 18:49:25');
INSERT INTO `projets` (`id`, `ref`, `title`, `service`, `parentProjectId`, `projectType`, `description`, `color`, `customColor`, `start`, `duration`, `lane`, `startExact`, `endExact`, `riskGain`, `budgetEstimate`, `prioritization`, `status`, `progression`, `youtrackId`, `youtrackUrl`, `ownerId`, `ownerDisplayName`, `ownerEmail`, `teamMembers`, `taskColumns`, `created_at`, `updated_at`) VALUES ('prj005','PRJ005','MIGRATION des contrats de LOGICA (90 polices)','Comptabilité / IT','prj5d94bf5b','Projet non transverse','Basculer les derniers contrats actifs prévoyance de l\'applicatif LOGICA vers OA.\nL\'obj est de pouvoir réaliser une coquille vide de produit permettant principalement de continuer à prélever nos adhérents et à assurer un reporting compagnie tel qu\'il existe aujourd\'hui. Les sinistres, s\'ils surviennent, seront gérés manuellement. Les contrats concernés seront resaisis et non migrés.',NULL,NULL,'2026-04-01',18,4,'2026-04-01','2026-12-31','Panne du serveur (obsolète)',NULL,'2026','Planifié',0,NULL,NULL,'Admin','Merouan Hamzaoui','m.hamzaoui@adep.com','[]','[\"idReadable\",\"summary\",\"assignee\",\"dueDate\",\"state\"]','2026-04-03 16:31:42','2026-04-04 18:49:25');
INSERT INTO `projets` (`id`, `ref`, `title`, `service`, `parentProjectId`, `projectType`, `description`, `color`, `customColor`, `start`, `duration`, `lane`, `startExact`, `endExact`, `riskGain`, `budgetEstimate`, `prioritization`, `status`, `progression`, `youtrackId`, `youtrackUrl`, `ownerId`, `ownerDisplayName`, `ownerEmail`, `teamMembers`, `taskColumns`, `created_at`, `updated_at`) VALUES ('prj006','PRJ006','Gestion Indus de prestations','Comptabilité / Prestations','prj5d94bf5b','Projet non transverse','Pas de possibilité de saisir des montants négatifs dans OA (rejets virements, remboursement CHU, remboursement indu).\nGestion manuelle par fichiers Excel : ne remonte pas dans les paiements compagnie.\nImpact : compta / presta / manque d’info relation client / fiabilité des données pour les assureurs.\n* Cahier des charges déjà effectué — voir nouveau recettage base Indu livré par SNL fév. 2026. VS est concerné au travers des reportings',NULL,NULL,'2026-02-01',6,7,'2026-02-01','2026-04-30',NULL,NULL,'enclenché','Planifié',60,NULL,NULL,'Admin','Merouan Hamzaoui','m.hamzaoui@adep.com','[]','[\"idReadable\",\"summary\",\"assignee\",\"dueDate\",\"state\"]','2026-04-03 16:31:42','2026-04-04 18:49:25');
INSERT INTO `projets` (`id`, `ref`, `title`, `service`, `parentProjectId`, `projectType`, `description`, `color`, `customColor`, `start`, `duration`, `lane`, `startExact`, `endExact`, `riskGain`, `budgetEstimate`, `prioritization`, `status`, `progression`, `youtrackId`, `youtrackUrl`, `ownerId`, `ownerDisplayName`, `ownerEmail`, `teamMembers`, `taskColumns`, `created_at`, `updated_at`) VALUES ('prj007','PRJ007','Passer les CB directement dans OA (intégration dans le compte contrat)','Comptabilité','prja45e47bd','Maintenance','Pour le paiement des impayés, le site Démat propose un lien Sogecommerce. Un WS intègre ensuite le paiement dans OA.\nL\'objectif est de pouvoir enregistrer un paiement client sans forcément passer par la démat pour éviter les problématiques de sécurité notamment. Les salariés se connecteront à OA pour initier un paiement sogecommerce client.\nMoins de manuel dans OA ; moins de double saisie.',NULL,NULL,'2026-10-01',6,25,'2026-10-01','2026-12-31',NULL,'2-3 K ? Devis à demander',NULL,'Planifié',0,NULL,NULL,'Admin','Merouan Hamzaoui','m.hamzaoui@adep.com','[]','[\"idReadable\",\"summary\",\"assignee\",\"dueDate\",\"state\"]','2026-04-03 16:31:42','2026-04-04 18:49:25');
