INSERT INTO `projets` (`id`, `ref`, `title`, `service`, `parentProjectId`, `projectType`, `description`, `color`, `customColor`, `start`, `duration`, `lane`, `startExact`, `endExact`, `riskGain`, `budgetEstimate`, `prioritization`, `status`, `progression`, `youtrackId`, `youtrackUrl`, `ownerId`, `ownerDisplayName`, `ownerEmail`, `teamMembers`, `taskColumns`, `created_at`, `updated_at`) VALUES ('prj009','PRJ009','Livre de caisse','Comptabilité','prj5d94bf5b',NULL,'Obj : Pouvoir saisir des fonds sans que les contrats soient validés + gestion des fonds des partenaires externes, fond de caisse et régul + génération des écritures comptables…\nÉviter les doubles saisies (gain de temps) et minimiser les écarts de caisse.\nPhase 1 : Déterminer dans quelle mesure le LDC ne rend pas le service attendu actuellement',NULL,NULL,'2026-09-15',7,9,'2026-09-15','2026-12-31',NULL,'7-8k approx','Quel est le besoin ? Refaire l\'étude','Planifié',0,NULL,NULL,'Admin','Merouan Hamzaoui','m.hamzaoui@adep.com','[]','[\"idReadable\",\"summary\",\"assignee\",\"dueDate\",\"state\"]','2026-04-03 16:31:42','2026-04-04 18:49:25');
