INSERT INTO `projets` (`id`, `ref`, `title`, `service`, `parentProjectId`, `projectType`, `description`, `color`, `customColor`, `start`, `duration`, `lane`, `startExact`, `endExact`, `riskGain`, `budgetEstimate`, `prioritization`, `status`, `progression`, `youtrackId`, `youtrackUrl`, `ownerId`, `ownerDisplayName`, `ownerEmail`, `teamMembers`, `taskColumns`, `created_at`, `updated_at`) VALUES ('prj041','PRJ041','Décommissionnement Site Portail PS','IT','prja45e47bd','Maintenance','Avec l\'ouverture du TP via Almerys, notre site dédié aux professionnels de santé devient inutile car il fait doublon avec celui d\'Almerys. L\'objectif est de le décommissionner proprement notamment en faisant une communication ciblée auprès des PS qui l\'utilisent toujours.',NULL,NULL,'2026-10-01',6,42,'2026-10-01','2026-12-31','Doublon de service / MCO d\'un serveur obsolète -> risque de sécurité IT','Interne','le service va s\'arrêter, dites nous pkoi vous en auriez l\'utilité','Planifié',0,NULL,NULL,'Admin','Merouan Hamzaoui','m.hamzaoui@adep.com','[]','[\"idReadable\",\"summary\",\"assignee\",\"dueDate\",\"state\"]','2026-04-03 16:31:42','2026-04-04 18:49:25');
INSERT INTO `projets` (`id`, `ref`, `title`, `service`, `parentProjectId`, `projectType`, `description`, `color`, `customColor`, `start`, `duration`, `lane`, `startExact`, `endExact`, `riskGain`, `budgetEstimate`, `prioritization`, `status`, `progression`, `youtrackId`, `youtrackUrl`, `ownerId`, `ownerDisplayName`, `ownerEmail`, `teamMembers`, `taskColumns`, `created_at`, `updated_at`) VALUES ('prj042','PRJ042','Outil Onboarding / OffBoarding IT','IT','prj5d94bf5b','Projet non transverse','Rationaliser et fluidifier l\'Onboarding et l\'Offboarding des collaborateurs. Obj :  unifier, tracer et automatiser \nces processus critiques, pour sécuriser les accès, fiabiliser les flux et libérer du temps aux \néquipes',NULL,NULL,'2026-01-01',26,18,'2026-01-01','2027-01-31','Sécurité IT / Perte de données / Image de marque (onboarding)','5,6K Setup + 7,6 Annuel',NULL,'Planifié',0,NULL,NULL,'Admin','Merouan Hamzaoui','m.hamzaoui@adep.com','[]','[\"idReadable\",\"summary\",\"assignee\",\"dueDate\",\"state\"]','2026-04-03 16:31:42','2026-04-04 18:49:25');
INSERT INTO `projets` (`id`, `ref`, `title`, `service`, `parentProjectId`, `projectType`, `description`, `color`, `customColor`, `start`, `duration`, `lane`, `startExact`, `endExact`, `riskGain`, `budgetEstimate`, `prioritization`, `status`, `progression`, `youtrackId`, `youtrackUrl`, `ownerId`, `ownerDisplayName`, `ownerEmail`, `teamMembers`, `taskColumns`, `created_at`, `updated_at`) VALUES ('prj043','PRJ043','Automatisation des flux FVA','Contrôle Interne','prja45e47bd','Evolution','Actuellement, les flux FVA sont intégrés automatiquement à la souscription par NOMA. \nNéanmoins, pour toutes les mises à jour de contrat sur OA, nous faisons chaque jour un export sur OA (Reporting > Auto > Fichier des Véhicules Assurés) que nous intégrons manuellement sur FVA (intégration par fichier).\nLe but serait de rendre cela automatique pour que nous ayons uniquement à traiter et vérifier les erreurs.',NULL,NULL,'2026-10-01',6,40,'2026-10-01','2026-12-31','Gain de productivité','Interne',NULL,'Planifié',0,NULL,NULL,'Admin','Merouan Hamzaoui','m.hamzaoui@adep.com','[]','[\"idReadable\",\"summary\",\"assignee\",\"dueDate\",\"state\"]','2026-04-03 16:31:42','2026-04-04 18:49:25');
INSERT INTO `projets` (`id`, `ref`, `title`, `service`, `parentProjectId`, `projectType`, `description`, `color`, `customColor`, `start`, `duration`, `lane`, `startExact`, `endExact`, `riskGain`, `budgetEstimate`, `prioritization`, `status`, `progression`, `youtrackId`, `youtrackUrl`, `ownerId`, `ownerDisplayName`, `ownerEmail`, `teamMembers`, `taskColumns`, `created_at`, `updated_at`) VALUES ('prj044','PRJ044','Automatisation des vérifications de PPE/gel dans l’outil Lexis Nexis (abo ViaSanté)','Contrôle Interne','prja45e47bd','Evolution','Actuellement, nous faisons une extraction quotidienne des AN qui arrivent via le pont démat pour nous assurer que les assurés ne sont pas des PPE. Nous utilisons le modèle de fichier définis par Lexis Nexis pour faire une intégration par batch. Nous traitons ensuite les alertes s’il y en a. \nLe but serait de rendre cela automatique pour que nous ayons uniquement à traiter et vérifier les erreurs.',NULL,NULL,'2026-10-01',6,41,'2026-10-01','2026-12-31','Gain de productivité','Interne',NULL,'Planifié',0,NULL,NULL,'Admin','Merouan Hamzaoui','m.hamzaoui@adep.com','[]','[\"idReadable\",\"summary\",\"assignee\",\"dueDate\",\"state\"]','2026-04-03 16:31:42','2026-04-04 18:49:25');
